const apiCall=async(sys,msg)=>{const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,system:sys,messages:[{role:"user",content:msg}]})});if(!r.ok)throw new Error(await r.text());const d=await r.json();return d.content?.map(b=>b.text||"").join("")||"";};
const safeCopy=(text)=>{try{if(navigator.clipboard&&window.isSecureContext){navigator.clipboard.writeText(text);return true;}const e=document.createElement("textarea");e.value=text;e.style.cssText="position:fixed;opacity:0;";document.body.appendChild(e);e.focus();e.select();document.execCommand("copy");document.body.removeChild(e);return true;}catch{return false;}};
const buildSys=(pid)=>{const p=PLATFORMS.find(x=>x.id===pid)||PLATFORMS[5];return`You are Lalakisskissbeam — master of the Skull Groove Multiversal Nexus. Build prompts for ${p.label}. RULES: Output MUST be ${p.min}–${p.max} words. Structure as labeled beats with duration timestamps: [BEAT 1 — 0.0s–2.0s] etc. ONE camera angle only. Name emotions explicitly. For transformation: exact START STATE then transition verb then exact END STATE. For magic: describe physical manifestation. Output the prompt ONLY — no preamble.`;};

function Particles({c}){const ref=useRef(null),ok=useRef(false);if(!ok.current){ok.current=true;setTimeout(()=>{const cv=ref.current;if(!cv)return;const ctx=cv.getContext("2d");cv.width=window.innerWidth;cv.height=window.innerHeight;const pts=Array.from({length:28},()=>({x:Math.random()*cv.width,y:Math.random()*cv.height,r:Math.random()*2+.5,dx:(Math.random()-.5)*.3,dy:-Math.random()*.4-.1,a:Math.random()*.4+.1}));const draw=()=>{ctx.clearRect(0,0,cv.width,cv.height);pts.forEach(p=>{ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=c+Math.floor(p.a*255).toString(16).padStart(2,"0");ctx.fill();p.x+=p.dx;p.y+=p.dy;p.a-=.0005;if(p.y<0||p.a<=0){p.y=cv.height+10;p.x=Math.random()*cv.width;p.a=Math.random()*.4+.1;}});requestAnimationFrame(draw);};draw();},200);}return<canvas ref={ref} style={{position:"fixed",inset:0,zIndex:0,pointerEvents:"none"}}/>;}
const Bubble=({text,color})=>(<div style={{display:"flex",gap:"12px",background:"rgba(8,8,16,0.92)",border:`1px solid ${color}55`,borderRadius:"10px",padding:"14px 18px",marginBottom:"20px",backdropFilter:"blur(12px)"}}><div style={{width:"40px",height:"40px",borderRadius:"50%",flexShrink:0,background:`radial-gradient(circle,${color}44,#080810)`,border:`2px solid ${color}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"17px"}}>💀</div><div><div style={{fontSize:"9px",color,letterSpacing:"0.18em",marginBottom:"3px",fontFamily:"'DM Mono',monospace",fontWeight:600}}>LALA · SKULL GROOVE NEXUS</div><div style={{fontSize:"14px",color:"#fff",fontFamily:"'Crimson Text',serif",fontStyle:"italic",lineHeight:1.6}}>"{text}"</div></div></div>);
const Tag=({label,active,color,onClick})=>(<button onClick={onClick} style={{padding:"7px 13px",borderRadius:"4px",cursor:"pointer",fontFamily:"'DM Mono',monospace",fontSize:"12px",border:active?`2px solid ${color}`:"2px solid #252535",background:active?`${color}28`:"#0e0e1a",color:active?color:"#ccc",transition:"all 0.12s",userSelect:"none",fontWeight:active?600:400}}>{label}</button>);
const Card=({num,title,sub,color,children})=>(<div style={{background:"#0c0c18",border:"1px solid #1e1e2e",borderRadius:"10px",padding:"20px",marginBottom:"12px"}}><div style={{display:"flex",alignItems:"center",gap:"10px",marginBottom:"13px"}}><div style={{width:"26px",height:"26px",borderRadius:"50%",background:`${color}28`,border:`2px solid ${color}88`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"11px",color,fontFamily:"'DM Mono',monospace",flexShrink:0,fontWeight:700}}>{num}</div><div><div style={{fontFamily:"'DM Mono',monospace",fontSize:"12px",color,letterSpacing:"0.13em",textTransform:"uppercase",fontWeight:600}}>{title}</div>{sub&&<div style={{fontFamily:"'DM Mono',monospace",fontSize:"10px",color:"#aaa",marginTop:"2px",lineHeight:1.4}}>{sub}</div>}</div></div>{children}</div>);
const Meter=({count,pid})=>{const p=PLATFORMS.find(x=>x.id===pid)||PLATFORMS[5];const pct=Math.min(count/p.max*100,100);const clr=count===0?"#2a2a3a":count<p.min?"#ffaa00":count<=p.max?"#44ff88":count<=400?"#ff8800":"#ff2244";const msg=count===0?"":count<p.min?"Short — more detail gives better results":count<=p.max?"✓ Great length — ready to generate!":count<=400?"Getting long — consider trimming":"Over the limit — split into two prompts";return(<div style={{marginTop:"10px"}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:"4px"}}><span style={{fontFamily:"'DM Mono',monospace",fontSize:"11px",color:clr}}>{msg}</span><span style={{fontFamily:"'DM Mono',monospace",fontSize:"11px",color:"#aaa"}}>{count}w / {p.max}w</span></div><div style={{height:"4px",background:"#1a1a2a",borderRadius:"2px"}}><div style={{height:"100%",width:`${pct}%`,background:clr,transition:"width 0.3s, background 0.3s",borderRadius:"2px"}}/></div></div>);};

