  const doCopy=()=>{if(!out)return;if(!safeCopy(out)){setExpTxt(out);setShowExp(true);}setCopied(true);setTimeout(()=>setCopied(false),2000);};
  const doExp=()=>{if(!out)return;setExpTxt(["SKULL GROOVE PROMPT ARCHITECT","=".repeat(36),`Platform: ${platData?.label}`,`Date: ${new Date().toLocaleString()}`,`Words: ${wc}`,"=".repeat(36),"",out,"","© Darrio · Grandmacyn · Skull Groove"].join("\n"));setShowExp(true);};
  const doRemix=async()=>{if(!out||loading)return;setLoading(true);try{setOut(await apiCall(buildSys(pid||"other"),`Remix this — same concept, different camera and pacing. Max ${platData.max} words:\n\n${out}`));}catch(e){setErr(e.message?.slice(0,200)||"Remix failed.");}setLoading(false);};

  const ta={width:"100%",background:"#080812",border:"2px solid #1e1e2e",borderRadius:"6px",color:"#fff",fontFamily:"'DM Mono',monospace",fontSize:"13px",padding:"11px 14px",resize:"vertical",outline:"none",boxSizing:"border-box",lineHeight:1.7};
  const bn=(a,c)=>({padding:"7px 15px",borderRadius:"4px",cursor:"pointer",fontFamily:"'DM Mono',monospace",fontSize:"11px",letterSpacing:"0.07em",textTransform:"uppercase",border:a?`2px solid ${c||mp}`:"2px solid #1e1e2e",background:a?`${c||mp}22`:"transparent",color:a?c||mp:"#ccc",transition:"all 0.15s",fontWeight:a?600:400});
  const bigB=(off,c)=>({width:"100%",padding:"15px",background:off?"#0e0e1a":c||mp,border:"none",borderRadius:"8px",color:off?"#444":"#000",fontFamily:"'Bebas Neue',sans-serif",fontSize:"20px",letterSpacing:"0.12em",cursor:off?"default":"pointer",transition:"all 0.2s",marginTop:"12px",fontWeight:700});
  const bg={minHeight:"100vh",background:mood.bg,transition:"background 0.7s",position:"relative",overflow:"hidden"};
  const orbs=<><div style={{position:"fixed",top:"-20%",right:"-15%",width:"70vw",height:"70vw",background:`radial-gradient(circle,${mood.o1}44 0%,transparent 65%)`,transition:"all 0.8s",borderRadius:"50%",zIndex:0,pointerEvents:"none"}}/><div style={{position:"fixed",bottom:"-25%",left:"-15%",width:"55vw",height:"55vw",background:`radial-gradient(circle,${mood.o2}33 0%,transparent 65%)`,transition:"all 0.8s",borderRadius:"50%",zIndex:0,pointerEvents:"none"}}/></>;
  const css=`@import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Mono:wght@300;400;500;600&family=Crimson+Text:ital,wght@0,400;1,400&display=swap');*{box-sizing:border-box;margin:0;padding:0;}button{outline:none;}::-webkit-scrollbar{width:4px;}::-webkit-scrollbar-thumb{background:#2a2a3a;}::placeholder{color:#666 !important;opacity:1;}@keyframes fadeUp{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}@keyframes pulse{0%,100%{opacity:.3}50%{opacity:.8}}@keyframes spin{to{transform:rotate(360deg)}}`;
  const td=TUT[tutStep]||TUT[0];
  const isRTL=L.dir==="rtl";
  const langBtn=<button onClick={()=>setShowLang(true)} style={{background:"#0c0c18",border:"1px solid #1e1e2e",borderRadius:"5px",padding:"6px 12px",cursor:"pointer",fontFamily:"'DM Mono',monospace",fontSize:"11px",color:"#ccc",display:"flex",alignItems:"center",gap:"7px"}}><span style={{fontSize:"16px"}}>{L.flag}</span><span>{L.name}</span><span style={{color:"#555"}}>▾</span></button>;

  const langModal=showLang&&(<div style={{position:"fixed",inset:0,zIndex:300,background:"#000000ee",display:"flex",alignItems:"center",justifyContent:"center",padding:"20px"}} onClick={()=>setShowLang(false)}><div style={{background:"#0c0c18",border:`2px solid ${mp}`,borderRadius:"14px",padding:"26px",maxWidth:"420px",width:"100%",maxHeight:"80vh",overflowY:"auto"}} onClick={e=>e.stopPropagation()}><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"22px",color:mp,textAlign:"center",marginBottom:"6px",letterSpacing:"0.1em"}}>{L.langTitle}</div><div style={{fontFamily:"'DM Mono',monospace",fontSize:"10px",color:"#aaa",textAlign:"center",marginBottom:"20px",lineHeight:1.7}}>{L.langNote}</div><div style={{display:"flex",flexDirection:"column",gap:"7px"}}>{Object.entries(LANGS).map(([id,lng])=>(<button key={id} onClick={()=>{setLangId(id);setShowLang(false);}} style={{padding:"12px 16px",borderRadius:"7px",cursor:"pointer",fontFamily:"'DM Mono',monospace",fontSize:"12px",border:langId===id?`2px solid ${mp}`:"2px solid #1e1e2e",background:langId===id?`${mp}22`:"#080812",color:langId===id?mp:"#ccc",display:"flex",alignItems:"center",gap:"11px",fontWeight:langId===id?600:400,transition:"all 0.15s"}}><span style={{fontSize:"20px"}}>{lng.flag}</span><span>{lng.name}</span>{langId===id&&<span style={{marginLeft:"auto",color:mp}}>✓</span>}</button>))}</div><button onClick={()=>setShowLang(false)} style={{marginTop:"14px",width:"100%",padding:"10px",background:"transparent",border:"2px solid #1e1e2e",color:"#aaa",fontFamily:"'DM Mono',monospace",fontSize:"11px",cursor:"pointer",borderRadius:"6px"}}>{L.close}</button></div></div>);
