  const bartModal=showB&&(<div style={{position:"fixed",inset:0,zIndex:200,background:"#000000cc",display:"flex",alignItems:"flex-end",justifyContent:"center",padding:"20px"}} onClick={()=>setShowB(false)}><div style={{background:"#0c0c18",border:`2px solid ${mp}`,borderRadius:"14px 14px 0 0",padding:"24px",maxWidth:"620px",width:"100%"}} onClick={e=>e.stopPropagation()}><div style={{display:"flex",alignItems:"center",gap:"12px",marginBottom:"14px"}}><div style={{width:"40px",height:"40px",borderRadius:"50%",background:`radial-gradient(circle,${mp}44,#080810)`,border:`2px solid ${mp}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"18px",flexShrink:0}}>🍹</div><div style={{flex:1}}><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"19px",color:mp,letterSpacing:"0.1em"}}>{L.bartTitle}</div><div style={{fontFamily:"'DM Mono',monospace",fontSize:"10px",color:"#aaa"}}>{L.bartSub}</div></div><button onClick={()=>setShowB(false)} style={{background:"transparent",border:"none",color:"#aaa",fontSize:"18px",cursor:"pointer"}}>✕</button></div>{bMsg&&<div style={{background:"#080812",border:"1px solid #1e1e2e",borderRadius:"7px",padding:"12px",marginBottom:"12px",fontFamily:"'Crimson Text',serif",fontSize:"14px",color:"#fff",lineHeight:1.75,fontStyle:"italic"}}>"{bMsg}"</div>}<textarea value={bIn} onChange={e=>setBIn(e.target.value)} placeholder={L.bartP} rows={3} style={ta}/><button onClick={doBart} disabled={bLoad||!bIn.trim()} style={{...bigB(!bIn.trim()),marginTop:"10px",fontSize:"16px"}}>{bLoad?L.bartThinking:L.bartAsk}</button></div></div>);

  const outBlock=out&&(<div style={{background:"#0c0c18",border:`2px solid ${mp}55`,borderRadius:"10px",padding:"20px",marginTop:"12px",animation:"fadeUp 0.3s ease"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"12px",flexWrap:"wrap",gap:"6px"}}><div style={{fontFamily:"'DM Mono',monospace",fontSize:"11px",color:mp,letterSpacing:"0.14em",fontWeight:600}}>{L.outTitle}</div><div style={{display:"flex",gap:"5px",flexWrap:"wrap"}}><button onClick={doCopy} style={bn(copied)}>{copied?L.copied:L.copy}</button><button onClick={doRemix} disabled={loading} style={bn(false)}>{L.remix}</button><button onClick={doExp} style={bn(false)}>{L.exportBtn}</button><button onClick={doSave} style={{...bn(saved),color:saved?"#44ff88":undefined}}>{saved?L.savedLbl:L.save}</button><button onClick={()=>{setBIn("");setBMsg("");setShowB(true);}} style={bn(false)}>{L.bart}</button></div></div><div style={{fontFamily:"'Crimson Text',serif",fontSize:"15px",color:"#fff",lineHeight:2,whiteSpace:"pre-wrap"}}>{out}</div><div style={{marginTop:"6px",fontFamily:"'DM Mono',monospace",fontSize:"10px",color:"#555",fontStyle:"italic"}}>{L.outNote}</div><Meter count={wc} pid={pid}/></div>);
  const errBlock=err&&(<div style={{background:"#180808",border:"2px solid #ff2244",borderRadius:"8px",padding:"12px",marginTop:"10px"}}><div style={{fontFamily:"'DM Mono',monospace",fontSize:"11px",color:"#ff2244",marginBottom:"4px",fontWeight:600}}>⚠ {L.errTitle}</div><div style={{fontFamily:"'DM Mono',monospace",fontSize:"10px",color:"#cc8888",lineHeight:1.6}}>{L.errSub}</div></div>);

  if(screen==="welcome")return(<div style={bg}><style>{css}</style>{orbs}<Particles c={mp}/>{langModal}{tutModal}<div style={{position:"relative",zIndex:1,minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",textAlign:"center",padding:"40px 24px"}} dir={isRTL?"rtl":"ltr"}><div style={{position:"absolute",top:"20px",right:"20px"}}>{langBtn}</div><div style={{fontSize:"clamp(80px,13vw,120px)",marginBottom:"20px",filter:`drop-shadow(0 0 50px ${mp}88)`,animation:"pulse 3s infinite"}}>💀</div><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"clamp(48px,9vw,90px)",color:"#B8860B",lineHeight:0.88,letterSpacing:"0.04em"}}>SKULL GROOVE</div><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"clamp(18px,3.5vw,32px)",color:"#7B44C2",letterSpacing:"0.22em",marginBottom:"14px"}}>MULTIVERSAL NEXUS</div><div style={{fontFamily:"'Crimson Text',serif",fontSize:"clamp(15px,2.5vw,19px)",color:"#ccc",fontStyle:"italic",marginBottom:"34px",maxWidth:"480px",lineHeight:1.5}}>{L.tagline}</div><div style={{fontFamily:"'DM Mono',monospace",fontSize:"12px",color:"#ccc",letterSpacing:"0.16em",marginBottom:"8px",fontWeight:500}}>{L.welcomeSub}</div><div style={{fontFamily:"'DM Mono',monospace",fontSize:"10px",color:"#888",marginBottom:"30px",letterSpacing:"0.1em"}}>{L.platforms}</div><button onClick={()=>setScreen("tier")} style={{padding:"16px 48px",background:"transparent",border:`3px solid ${mp}`,color:mp,fontFamily:"'Bebas Neue',sans-serif",fontSize:"22px",letterSpacing:"0.2em",cursor:"pointer",borderRadius:"6px",transition:"all 0.2s",boxShadow:`0 0 40px ${mp}33`}} onMouseEnter={e=>e.currentTarget.style.background=mp+"28"} onMouseLeave={e=>e.currentTarget.style.background="transparent"}>{L.enter}</button><button onClick={()=>{setTutStep(0);setTutOpen(true);}} style={{marginTop:"14px",background:"transparent",border:"none",color:"#888",fontFamily:"'DM Mono',monospace",fontSize:"11px",cursor:"pointer",letterSpacing:"0.14em"}}>{L.howto}</button></div></div>);

